fn read_real_file_version(path: &Path) -> PlatformResult<Option<VersionMetadata>> {
    let quoted = powershell_single_quoted(&path.display().to_string());
    let script = format!(
        "$item = Get-Item -LiteralPath {quoted} -ErrorAction Stop; $version = $item.VersionInfo; if ($version.FileVersionRaw) {{ Write-Output \"$($version.FileMajorPart).$($version.FileMinorPart).$($version.FileBuildPart).$($version.FilePrivatePart)`t$($version.FileVersion)\" }}"
    );
    let output = run_powershell(
        PlatformOperation::ReadVersionMetadata,
        path.display().to_string(),
        &script,
    )?;
    let trimmed = output.trim();
    if trimmed.is_empty() {
        return Ok(None);
    }
    let (semantic, raw) = parse_version_line(trimmed).map_err(|diagnostic| {
        PlatformError::parse_error(
            PlatformOperation::ReadVersionMetadata,
            path.display().to_string(),
