#[cfg(windows)]
fn read_real_system_metadata() -> PlatformResult<SystemMetadata> {
    let os_output = run_powershell(
        PlatformOperation::ReadSystemMetadata,
        "Win32_OperatingSystem",
        r#"Get-CimInstance Win32_OperatingSystem | Select-Object -First 1 | ForEach-Object { "$($_.Caption)`t$($_.Version)`t$($_.TotalVisibleMemorySize)" }"#,
    )?;
    let cpu_output = run_powershell(
        PlatformOperation::ReadSystemMetadata,
        "Win32_Processor",
        r#"Get-CimInstance Win32_Processor | Select-Object -First 1 | ForEach-Object { "$($_.Name)" }"#,
    )?;

    let mut os_parts = os_output.trim().split('\t');
    let os_name = os_parts.next().unwrap_or("Windows").trim();
    let os_version = os_parts
        .next()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_owned);
    let physical_memory_bytes = os_parts
        .next()
        .and_then(|value| value.trim().parse::<u64>().ok())
        .and_then(|kilobytes| kilobytes.checked_mul(1024));

    Ok(SystemMetadata::new(
        if os_name.is_empty() { "Windows" } else { os_name },
        os_version,
        std::env::consts::ARCH,
        Some(cpu_output.trim()).filter(|value| !value.is_empty()),
        physical_memory_bytes,
        std::thread::available_parallelism().ok().map(usize::from),
    ))
