#[cfg(windows)]
fn run_powershell(
    operation: PlatformOperation,
    target: impl Into<String>,
    script: &str,
) -> PlatformResult<String> {
    use std::process::Command;

    let target = target.into();
    let output = Command::new("powershell")
        .args(["-NoProfile", "-NonInteractive", "-Command", script])
        .output()
        .map_err(|error| PlatformError::from_io(operation, target.clone(), &error))?;

    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        return Err(PlatformError::command_failed(
            operation,
            target,
            stderr.trim().to_owned(),
        ));
    }

    String::from_utf8(output.stdout)
        .map_err(|error| PlatformError::parse_error(operation, target, error.to_string()))
}

#[cfg(windows)]
fn parse_process_line(line: &str) -> PlatformResult<ProcessInfo> {
    let mut parts = line.splitn(4, '\t');
    let pid = parse_u32_field(parts.next(), "pid")?;
    let parent_pid = match parts.next().map(str::trim).filter(|value| !value.is_empty()) {
        Some(value) => Some(u32::from_str(value).map_err(|error| {
            PlatformError::parse_error(
                PlatformOperation::ListProcesses,
                "process table",
                format!("invalid parent pid '{value}': {error}"),
            )
        })?),
        None => None,
    };
    let name = parts.next().unwrap_or_default().trim().to_owned();
    let executable_path = parts
        .next()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(PathBuf::from);

    Ok(ProcessInfo::new(pid, parent_pid, name, executable_path))
}

#[cfg(windows)]
fn parse_u32_field(value: Option<&str>, name: &str) -> PlatformResult<u32> {
    let value = value.map(str::trim).filter(|value| !value.is_empty()).ok_or_else(|| {
        PlatformError::parse_error(
            PlatformOperation::ListProcesses,
            "process table",
            format!("missing {name}"),
        )
    })?;
    u32::from_str(value).map_err(|error| {
        PlatformError::parse_error(
            PlatformOperation::ListProcesses,
            "process table",
            format!("invalid {name} '{value}': {error}"),
        )
    })
}

#[cfg(windows)]
fn parse_version_line(line: &str) -> Result<(SemanticVersion, Option<String>), String> {
    let mut parts = line.splitn(2, '\t');
    let numeric = parts.next().unwrap_or_default();
    let raw = parts
        .next()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_owned);
    let mut numbers = numeric.split('.');
    let major = parse_version_component(numbers.next(), "major")?;
    let minor = parse_version_component(numbers.next(), "minor")?;
    let patch = parse_version_component(numbers.next(), "patch")?;
    Ok((SemanticVersion::new(major, minor, patch), raw))
}

#[cfg(windows)]
fn parse_version_component(value: Option<&str>, name: &str) -> Result<u64, String> {
    value
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .ok_or_else(|| format!("missing {name} version component"))
        .and_then(|value| {
            u64::from_str(value)
                .map_err(|error| format!("invalid {name} version component '{value}': {error}"))
        })
}

#[cfg(windows)]
fn powershell_single_quoted(value: &str) -> String {
    format!("'{}'", value.replace(''', "''"))
}

#[cfg(test)]
mod tests {
    use crate::platform::{PlatformErrorKind, PlatformOperation};

    use super::*;

    #[derive(Debug, Clone)]
    struct FakeProcessInspector {
        processes: PlatformResult<Vec<ProcessInfo>>,
        version: PlatformResult<Option<VersionMetadata>>,
        system: PlatformResult<SystemMetadata>,
    }

    impl Default for FakeProcessInspector {
        fn default() -> Self {
            Self {
                processes: Ok(Vec::new()),
                version: Ok(None),
                system: Ok(SystemMetadata::new(
                    "Windows",
                    Some("10.0"),
                    "x86_64",
                    Some("Fake CPU"),
                    Some(16 * 1024 * 1024 * 1024),
                    Some(8),
                )),
            }
        }
    }

    impl ProcessInspector for FakeProcessInspector {
        fn list_processes(&self) -> PlatformResult<Vec<ProcessInfo>> {
            self.processes.clone()
        }

        fn file_version(&self, _path: &Path) -> PlatformResult<Option<VersionMetadata>> {
            self.version.clone()
        }

        fn system_metadata(&self) -> PlatformResult<SystemMetadata> {
            self.system.clone()
        }
    }

    #[test]
    fn fake_process_inspector_supports_manager_detection_inputs() {
        let inspector = FakeProcessInspector {
            processes: Ok(vec![
                ProcessInfo::new(7, Some(3), "ModOrganizer.exe", Some(r"C:\MO2\ModOrganizer.exe")),
                ProcessInfo::new(9, Some(7), "cmt-rs.exe", Some(r"C:\Tools\cmt-rs.exe")),
            ]),
            version: Ok(Some(VersionMetadata::new(
                SemanticVersion::new(2, 5, 2),
                Some("2.5.2.0"),
            ))),
            ..Default::default()
        };

        let processes = inspector
            .list_processes()
            .expect("fake process list should be available");
        let manager = processes
            .iter()
            .find(|process| process.name == "ModOrganizer.exe")
            .expect("fake MO2 process should be present");
        let version = inspector
            .file_version(manager.executable_path.as_deref().expect("fake exe path"))
            .expect("fake version should be available")
            .expect("fake version metadata should exist");

        assert_eq!(manager.parent_pid, Some(3));
        assert_eq!(version.semantic, SemanticVersion::new(2, 5, 2));
        assert_eq!(version.raw.as_deref(), Some("2.5.2.0"));
    }

    #[test]
    fn fake_process_inspector_returns_typed_system_failures() {
        let inspector = FakeProcessInspector {
            system: Err(PlatformError::new(
                PlatformOperation::ReadSystemMetadata,
                "fake specs",
                PlatformErrorKind::CommandFailed,
                "System metadata read failed.",
            )),
            ..Default::default()
        };

        let error = inspector
            .system_metadata()
            .expect_err("fake system metadata failure should be typed");

        assert_eq!(error.operation, PlatformOperation::ReadSystemMetadata);
        assert_eq!(error.kind, PlatformErrorKind::CommandFailed);
        assert_eq!(error.user_message(), "System metadata read failed.");
    }

    #[cfg(not(windows))]
    #[test]
    fn real_process_operations_are_explicitly_unsupported_off_windows() {
        let inspector = RealProcessInspector::new();

        let process_error = inspector
            .list_processes()
            .expect_err("non-Windows process inspection should be unsupported");
        let version_error = inspector
            .file_version(Path::new("ModOrganizer.exe"))
            .expect_err("non-Windows version metadata should be unsupported");
        let system_error = inspector
            .system_metadata()
            .expect_err("non-Windows system metadata should be unsupported");

        assert_eq!(process_error.kind, PlatformErrorKind::UnsupportedPlatform);
        assert_eq!(version_error.kind, PlatformErrorKind::UnsupportedPlatform);
        assert_eq!(system_error.kind, PlatformErrorKind::UnsupportedPlatform);
        assert_eq!(
            process_error.user_message(),
            "Process inspection is not supported on this platform."
        );
    }

    #[cfg(windows)]
    #[test]
    fn parser_handles_powershell_process_rows() {
        let process = parse_process_line("10\t5\tVortex.exe\tC:\\Vortex\\Vortex.exe")
            .expect("process row should parse");

        assert_eq!(process.pid, 10);
        assert_eq!(process.parent_pid, Some(5));
        assert_eq!(process.name, "Vortex.exe");
        assert_eq!(
            process.executable_path,
            Some(PathBuf::from(r"C:\Vortex\Vortex.exe"))
        );
    }

    #[cfg(windows)]
    #[test]
    fn parser_uses_first_three_file_version_components() {
        let (semantic, raw) = parse_version_line("2.5.2.0\t2.5.2.0")
            .expect("version line should parse");

        assert_eq!(semantic, SemanticVersion::new(2, 5, 2));
        assert_eq!(raw.as_deref(), Some("2.5.2.0"));
    }
}

