    let mut numbers = numeric.split('.');
    let major = parse_version_component(numbers.next(), "major")?;
    let minor = parse_version_component(numbers.next(), "minor")?;
    let patch = parse_version_component(numbers.next(), "patch")?;
    Ok((SemanticVersion::new(major, minor, patch), raw))
}

#[cfg(windows)]
fn parse_version_component(value: Option<&str>, name: &str) -> Result<u64, String> {
    value
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .ok_or_else(|| format!("missing {name} version component"))
        .and_then(|value| {
            u64::from_str(value)
                .map_err(|error| format!("invalid {name} version component '{value}': {error}"))
        })
}

#[cfg(windows)]
fn powershell_single_quoted(value: &str) -> String {
    format!("'{}'", value.replace(''', "''"))
}

