fn parse_process_line(line: &str) -> PlatformResult<ProcessInfo> {
    let mut parts = line.splitn(4, '\t');
    let pid = parse_u32_field(parts.next(), "pid")?;
    let parent_pid = match parts.next().map(str::trim).filter(|value| !value.is_empty()) {
        Some(value) => Some(u32::from_str(value).map_err(|error| {
            PlatformError::parse_error(
                PlatformOperation::ListProcesses,
                "process table",
                format!("invalid parent pid '{value}': {error}"),
            )
        })?),
        None => None,
    };
    let name = parts.next().unwrap_or_default().trim().to_owned();
    let executable_path = parts
        .next()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(PathBuf::from);

    Ok(ProcessInfo::new(pid, parent_pid, name, executable_path))
}

#[cfg(windows)]
fn parse_u32_field(value: Option<&str>, name: &str) -> PlatformResult<u32> {
    let value = value.map(str::trim).filter(|value| !value.is_empty()).ok_or_else(|| {
        PlatformError::parse_error(
            PlatformOperation::ListProcesses,
            "process table",
            format!("missing {name}"),
        )
    })?;
    u32::from_str(value).map_err(|error| {
        PlatformError::parse_error(
            PlatformOperation::ListProcesses,
            "process table",
            format!("invalid {name} '{value}': {error}"),
        )
    })
}

#[cfg(windows)]
fn parse_version_line(line: &str) -> Result<(SemanticVersion, Option<String>), String> {
    let mut parts = line.splitn(2, '\t');
    let numeric = parts.next().unwrap_or_default();
    let raw = parts
        .next()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_owned);
    let mut numbers = numeric.split('.');
    let major = parse_version_component(numbers.next(), "major")?;
    let minor = parse_version_component(numbers.next(), "minor")?;
    let patch = parse_version_component(numbers.next(), "patch")?;
    Ok((SemanticVersion::new(major, minor, patch), raw))
}

