#[cfg(windows)]
fn read_real_registry_string(request: &RegistryValueRequest) -> PlatformResult<Option<String>> {
    use std::process::Command;

    let key = format!("{}\\{}", request.hive.as_reg_query_prefix(), request.subkey);
    let output = Command::new("reg")
        .args(["query", &key, "/v", &request.value_name])
        .output()
        .map_err(|error| {
            PlatformError::from_io(PlatformOperation::ReadRegistry, request.target(), &error)
        })?;

    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        let stdout = String::from_utf8_lossy(&output.stdout);
        let diagnostic = format!("{}{}", stdout.trim(), stderr.trim());
        if diagnostic.to_ascii_lowercase().contains("unable to find") {
            return Ok(None);
        }
        return Err(PlatformError::command_failed(
            PlatformOperation::ReadRegistry,
            request.target(),
            diagnostic,
        ));
    }

    let stdout = String::from_utf8(output.stdout).map_err(|error| {
        PlatformError::parse_error(
            PlatformOperation::ReadRegistry,
            request.target(),
            error.to_string(),
        )
    })?;

    parse_reg_query_string_value(&stdout, &request.value_name).ok_or_else(|| {
        PlatformError::parse_error(
            PlatformOperation::ReadRegistry,
            request.target(),
            "REG_SZ value was not present in reg query output",
        )
    })
}

#[cfg(windows)]
fn parse_reg_query_string_value(output: &str, value_name: &str) -> Option<Option<String>> {
    for line in output.lines() {
        let trimmed = line.trim_start();
        if !trimmed.starts_with(value_name) {
            continue;
        }
        let reg_sz_index = trimmed.find("REG_SZ")?;
        let value = trimmed[reg_sz_index + "REG_SZ".len()..].trim();
        return Some(if value.is_empty() {
            None
        } else {
            Some(value.to_owned())
        });
    }
    None
}

